import * as React from 'react'
import { cva, type VariantProps } from 'class-variance-authority'
import { cn } from '../lib/utils'

const badgeVariants = cva(
  'inline-flex items-center px-2.5 py-0.5 text-xs font-medium uppercase tracking-widest transition-colors',
  {
    variants: {
      variant: {
        default: 'bg-foreground text-background',
        outline: 'border-2 border-foreground bg-transparent text-foreground',
        destructive: 'bg-destructive text-destructive-foreground',
        pill: 'rounded-sm bg-foreground text-background',
      },
    },
    defaultVariants: {
      variant: 'default',
    },
  }
)

export interface BadgeProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return <div className={cn(badgeVariants({ variant }), className)} {...props} />
}

export { Badge, badgeVariants }
